		&lt;tr&gt;
			&lt;td style=&quot;height:12px; width:257px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;Jahangir- Fourth Mughal Emperor&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;height:12px; width:257px&quot;&gt;
