&lt;/table&gt;<br><br>&lt;ul&gt;
	&lt;li&gt;नूर जहाँ, चौथे मुगल सम्राट जहांगीर की बीसवीं और अंतिम पत्नी थीं।&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width: 300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;height:21px; width:261px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;&lt;strong&gt;मुगल सम्राट&lt;/strong&gt;&lt;/p&gt;
