&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;64&lt;/strong&gt;&lt;/u&gt; है।&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;ग्लोबल यूनिकॉर्न इंडेक्स 2025: सबसे अधिक बिलियन डॉलर वाले स्टार्टअप वाले शीर्ष 10 देश।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;322&quot; data-start=&quot;169&quot;&gt;
	&lt;p data-end=&quot;322&quot; data-start=&quot;171&quot;&gt;&lt;strong data-end=&quot;182&quot; data-start=&quot;174&quot;&gt;2025&lt;/strong&gt; में, &lt;strong data-end=&quot;212&quot; data-start=&quot;188&quot;&gt;वैश्विक यूनिकॉर्न की संख्या&lt;/strong&gt; &lt;strong data-end=&quot;248&quot; data-start=&quot;223&quot;&gt;रिकॉर्ड 1,523 स्टार्टअप&lt;/strong&gt; तक पहुंच जाएगी, जिनमें &lt;strong data-end=&quot;284&quot; data-start=&quot;265&quot;&gt;से प्रत्येक का मूल्य 1 बिलियन डॉलर&lt;/strong&gt; से अधिक होगा, कुल मिलाकर इसका मूल्य &lt;strong data-end=&quot;312&quot; data-start=&quot;295&quot;&gt;5.6 ट्रिलियन डॉलर&lt;/strong&gt; होगा।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;446&quot; data-start=&quot;323&quot;&gt;
	&lt;p data-end=&quot;446&quot; data-start=&quot;325&quot;&gt;&lt;strong data-end=&quot;338&quot; data-start=&quot;327&quot;&gt;यूनिकॉर्न&lt;/strong&gt; एक &lt;strong data-end=&quot;370&quot; data-start=&quot;344&quot;&gt;निजी स्वामित्व वाला स्टार्टअप&lt;/strong&gt; है जिसका &lt;strong data-end=&quot;407&quot; data-start=&quot;378&quot;&gt;मूल्यांकन 1 बिलियन डॉलर से अधिक है&lt;/strong&gt; - यह शब्द &lt;strong data-end=&quot;445&quot; data-start=&quot;423&quot;&gt;2013 में ऐलीन ली&lt;/strong&gt; द्वारा गढ़ा गया था।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;543&quot; data-start=&quot;447&quot;&gt;
