	&lt;li data-end=&quot;711&quot; data-start=&quot;544&quot;&gt;
	&lt;p data-end=&quot;623&quot; data-start=&quot;546&quot;&gt;&lt;strong data-end=&quot;553&quot; data-start=&quot;546&quot;&gt;संयुक्त राज्य अमेरिका&lt;/strong&gt; &lt;strong data-end=&quot;581&quot; data-start=&quot;565&quot;&gt;758 यूनिकॉर्न&lt;/strong&gt; के साथ शीर्ष पर है, जिनमें &lt;strong data-end=&quot;620&quot; data-start=&quot;593&quot;&gt;विश्व की शीर्ष 10 में से 6&lt;/strong&gt; शामिल हैं।&lt;/p&gt;

	&lt;ul data-end=&quot;711&quot; data-start=&quot;626&quot;&gt;
		&lt;li data-end=&quot;711&quot; data-start=&quot;626&quot;&gt;
		&lt;p data-end=&quot;711&quot; data-start=&quot;628&quot;&gt;&lt;strong data-end=&quot;645&quot; data-start=&quot;628&quot;&gt;सैन फ्रांसिस्को&lt;/strong&gt; &lt;strong data-end=&quot;678&quot; data-start=&quot;653&quot;&gt;#1 यूनिकॉर्न शहर (199)&lt;/strong&gt; है, उसके बाद &lt;strong data-end=&quot;710&quot; data-start=&quot;692&quot;&gt;न्यूयॉर्क (142)&lt;/strong&gt; है।&lt;/p&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;823&quot; data-start=&quot;712&quot;&gt;
	&lt;p data-end=&quot;823&quot; data-start=&quot;714&quot;&gt;&lt;strong data-end=&quot;723&quot; data-start=&quot;714&quot;&gt;चीन&lt;/strong&gt; &lt;strong data-end=&quot;755&quot; data-start=&quot;739&quot;&gt;343 यूनिकॉर्न&lt;/strong&gt; के साथ दूसरे स्थान पर है, और &lt;strong data-end=&quot;789&quot; data-start=&quot;761&quot;&gt;शीर्ष 10 यूनिकॉर्न में से 3&lt;/strong&gt; : &lt;strong data-end=&quot;822&quot; data-start=&quot;791&quot;&gt;बाइटडांस, एंट ग्रुप, शीन&lt;/strong&gt;&amp;nbsp;&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1001&quot; data-start=&quot;824&quot;&gt;
	&lt;p data-end=&quot;879&quot; data-start=&quot;826&quot;&gt;&lt;strong data-end=&quot;835&quot; data-start=&quot;826&quot;&gt;भारत&lt;/strong&gt; &lt;strong data-end=&quot;878&quot; data-start=&quot;863&quot;&gt;64 यूनिकॉर्न के&lt;/strong&gt; साथ &lt;strong data-end=&quot;857&quot; data-start=&quot;842&quot;&gt;विश्व स्तर पर तीसरे&lt;/strong&gt; स्थान पर है।&lt;/p&gt;

	&lt;ul data-end=&quot;1001&quot; data-start=&quot;882&quot;&gt;
		&lt;li data-end=&quot;1001&quot; data-start=&quot;882&quot;&gt;
		&lt;p data-end=&quot;1001&quot; data-start=&quot;884&quot;&gt;&lt;strong data-end=&quot;897&quot; data-start=&quot;884&quot;&gt;बेंगलुरु&lt;/strong&gt; भारत का शीर्ष यूनिकॉर्न हब है ( &lt;strong data-end=&quot;946&quot; data-start=&quot;926&quot;&gt;विश्व स्तर पर 7वां स्थान&lt;/strong&gt; ), इसके बाद &lt;strong data-end=&quot;977&quot; data-start=&quot;961&quot;&gt;मुंबई (22वां)&lt;/strong&gt; और &lt;strong data-end=&quot;1000&quot; data-start=&quot;982&quot;&gt;गुरुग्राम (27वां) का स्थान है&lt;/strong&gt; ।&lt;/p&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1140&quot; data-start=&quot;1002&quot;&gt;
	&lt;p data-end=&quot;1065&quot; data-start=&quot;1004&quot;&gt;&lt;strong data-end=&quot;1026&quot; data-start=&quot;1004&quot;&gt;फिनटेक और गेमिंग&lt;/strong&gt; भारत में मुख्य यूनिकॉर्न क्षेत्र हैं:&lt;/p&gt;

	&lt;ul data-end=&quot;1140&quot; data-start=&quot;1068&quot;&gt;
		&lt;li data-end=&quot;1091&quot; data-start=&quot;1068&quot;&gt;
		&lt;p data-end=&quot;1091&quot; data-start=&quot;1070&quot;&gt;&lt;strong data-end=&quot;1081&quot; data-start=&quot;1070&quot;&gt;जीरोधा&lt;/strong&gt; &amp;ndash; $8.2B&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1115&quot; data-start=&quot;1094&quot;&gt;
