	&lt;li&gt;Capital of Bhutan -&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;Thimphu&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Lotay Tshering&lt;/span&gt;&amp;nbsp;is the current&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Prime minister of Bhutan&lt;/span&gt;.(As of Sept 2022)&lt;/li&gt;
